import json

def check_inputs(ftp_config, db_connection, api_key, monitoring_platform_url, alert_recipients=None):
    errors = []

    # 检查必需参数
    if not ftp_config:
        errors.append("FTP配置信息不能为空")
    if not db_connection:
        errors.append("数据库连接配置不能为空")
    if not api_key:
        errors.append("API密钥不能为空")
    if not monitoring_platform_url:
        errors.append("监控平台URL不能为空")

    # 验证FTP配置格式
    try:
        ftp_data = json.loads(ftp_config)
        required_ftp_fields = ['host', 'username', 'password', 'path']
        for field in required_ftp_fields:
            if field not in ftp_data:
                errors.append(f"FTP配置缺少字段: {field}")
    except json.JSONDecodeError:
        errors.append("FTP配置不是有效的JSON格式")

    # 验证数据库连接格式
    try:
        db_data = json.loads(db_connection)
        required_db_fields = ['host', 'database', 'username', 'password']
        for field in required_db_fields:
            if field not in db_data:
                errors.append(f"数据库配置缺少字段: {field}")
    except json.JSONDecodeError:
        errors.append("数据库配置不是有效的JSON格式")

    return {
        "valid": len(errors) == 0,
        "errors": errors,
        "ftp_config": ftp_data if 'ftp_data' in locals() else None,
        "db_config": db_data if 'db_data' in locals() else None
    }

