import pandas as pd
import numpy as np
from datetime import datetime

def analyze_risks(cleaned_data, geolocation_results):
    """分析日志数据中的风险"""
    all_anomalies = []
    risk_summary = {
        "high_risk": 0,
        "medium_risk": 0,
        "low_risk": 0,
        "total_events": 0
    }

    for data in cleaned_data:
        df = pd.DataFrame(data['dataframe'])

        # 风险分析规则
        anomalies = []

        # 1. 高频访问检测（假设有timestamp和user_id列）
        if 'timestamp' in df.columns and 'user_id' in df.columns:
            df['timestamp'] = pd.to_datetime(df['timestamp'])
            df['hour'] = df['timestamp'].dt.hour

            # 计算每个用户每小时的活动次数
            user_hourly_counts = df.groupby(['user_id', 'hour']).size().reset_index(name='count')

            # 标记高频访问（超过50次/小时）
            high_freq = user_hourly_counts[user_hourly_counts['count'] > 50]
            for _, row in high_freq.iterrows():
                anomalies.append({
                    "type": "high_frequency_access",
                    "user_id": row['user_id'],
                    "hour": row['hour'],
                    "count": row['count'],
                    "risk_level": "high",
                    "description": f"用户{row['user_id']}在{row['hour']}时访问次数异常: {row['count']}次"
                })

        # 2. 异常时间访问（凌晨2-5点）
        if 'timestamp' in df.columns:
            night_access = df[df['timestamp'].dt.hour.between(2, 5)]
            if len(night_access) > 10:
                anomalies.append({
                    "type": "night_access",
                    "count": len(night_access),
                    "risk_level": "medium",
                    "description": f"在凌晨2-5点检测到{len(night_access)}次访问"
                })

        # 3. 地理异常（如果IP地理位置数据可用）
        if 'ip_address' in df.columns and geolocation_results:
            # 这里简化处理，实际应该使用真实的地理位置API结果
            foreign_ips = df[~df['ip_address'].str.startswith(('192.168', '10.', '172.'))]
            if len(foreign_ips) > 0:
                anomalies.append({
                    "type": "foreign_ip_access",
                    "count": len(foreign_ips),
                    "risk_level": "medium",
                    "description": f"检测到{len(foreign_ips)}次来自非内网IP的访问"
                })

        # 4. 失败登录尝试（假设有action和status列）
        if 'action' in df.columns and 'status' in df.columns:
            failed_logins = df[(df['action'] == 'login') & (df['status'] == 'failed')]
            if len(failed_logins) > 5:
                anomalies.append({
                    "type": "failed_login_attempts",
                    "count": len(failed_logins),
                    "risk_level": "high",
                    "description": f"检测到{len(failed_logins)}次登录失败尝试"
                })

        all_anomalies.extend(anomalies)

        # 更新风险统计
        for anomaly in anomalies:
            if anomaly['risk_level'] == 'high':
                risk_summary['high_risk'] += 1
            elif anomaly['risk_level'] == 'medium':
                risk_summary['medium_risk'] += 1
            else:
                risk_summary['low_risk'] += 1

        risk_summary['total_events'] += len(df)

    return {
        "anomalies": all_anomalies,
        "risk_summary": risk_summary,
        "total_anomalies": len(all_anomalies),
        "analysis_time": datetime.now().isoformat()
    }
